import{_ as p,o as a,c as e,j as r,a as t,a1 as T}from"./chunks/framework.Bp7r_-XI.js";const i=JSON.parse('{"title":"破梦机：OT-A09","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/7.载具及随从/载具/6.可升级/破梦机：OT-A09.md","filePath":"4.资源分区/7.物品与装备/7.载具及随从/载具/6.可升级/破梦机：OT-A09.md"}'),A={name:"4.资源分区/7.物品与装备/7.载具及随从/载具/6.可升级/破梦机：OT-A09.md"};function O(o,b,n,s,d,l){return a(),e("div",null,[...b[0]||(b[0]=[r("h1",{id:"破梦机-ot-a09",tabindex:"-1"},[t("破梦机：OT-A09 "),r("a",{class:"header-anchor",href:"#破梦机-ot-a09","aria-label":'Permalink to "破梦机：OT-A09"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：汹涌疾风028")])])],-1),T('<h1 id="破梦机-ot-a09-1" tabindex="-1">破梦机：OT-A09 <a class="header-anchor" href="#破梦机-ot-a09-1" aria-label="Permalink to &quot;破梦机：OT-A09&quot;">​</a></h1><p>破梦机<br> 描述：当幻想粒子聚集到一定程度时，就会降落到城市里与人脑的海马体产生反应，将人的梦境（潜意识）化作现实。这种幻想粒子聚合而成的雾团，被称之为梦雾。<br> ——————————————<br> 破梦机正是用于进入梦雾的飞行器，本质是以现实为蓝图干涉潜意识，在化作现实的梦境中乘坐破梦机，以此使用自带的粒子干涉功能进行解析、收集、激将自然梦雾中的粒子引入人造梦雾，以此稀释梦雾浓度，从而减少损害。<br> ——————————————<br> 值得一提的是，破梦机实际上是在群体潜意识中构造的共识，以数据形式存在于人造梦雾之中，主神为兑换者提供了人工展开梦雾的能力，在使用者的潜意识中植入了破梦机的数据，以便兑换者在影片中具现并使用破梦机进行战斗。</p><p>破梦机：OT-A09<br> 价格：D+500<br> 分类：机械载具<br> 描述：作为首批被&quot;制造”的破梦机，OT-A09的设计还是摆脱不了对现实飞行器的模仿。虽然已经意识到在梦中飞行根本不需要考虑气动外型，但出于设计者对固定翼的执念，OT- A09还是有类似机翼的设计。<br> 该型号初衷用作研究，配备了远超同期性能的粒子收集器和运算模块，能一边进行破梦边进行巨量的数据分析。在“击破凝聚体是最有效的收集手段&quot;的观念得到重视后，运用自身超高计算力和大收集量这一优势，使其在战斗中能快速利用粒子生成密集的火力，进行打击。</p><p>护甲值：12<br> 结构值：22<br> 体积：20<br> 移动速度：40米/轮<br> 载员：驾驶员1名，乘员2名，总体积不超过15<br> 动力系统：无限动力<br> 移动模式：地面，空中（机动性普通）</p><p>特性：脉冲炮/轨道炮，慢启动，重型载具</p><p>【脉冲炮/轨道炮】：这视为一个单独的配件，需要额外支付250分才能加装。加装后你可以消费1意志力主动为OT-A09凝聚出武装实体，随后在该场景内，每轮开始时驾驶员可以自行选择本轮使用脉冲炮或是轨道炮进行攻击，使用不同武器时会占用对应槽位。</p><p>脉冲炮<br> 占用：武器槽位（两侧）<br> 分类：远程武器<br> 武器伤害：5L<br> 武器特性：【高速5】【破甲3】<br> 伤害类型：物理-穿刺<br> 基础射程：200米<br> 速射等级：无<br> 弹容量：【无限子弹】</p><p>轨道炮<br> 占用：武器槽位（左侧）<br> 分类：远程武器<br> 武器伤害：4L<br> 武器特性：【高速5】【贯穿】<br> 伤害类型：光能-能量伤害<br> 基础射程：100米<br> 速射等级：连射<br> 弹容量：【无限子弹】</p><p>【慢启动】：OT-A09需要驾驶员使用移动动作展开人造梦雾区域，随后才能在本场景内正常作为载具使用。未启动时，OT-A09不具有除【重型载具】以外的所有特性。</p><p>【重型载具】：OT-A09会为驾驶者和乘客提供全遮蔽效果，同时额外为驾驶者和乘客提供遮蔽防御，其数值为载具体积/被遮蔽者体积取低。<br> OT-A09具有左侧与右侧各一个武器槽位，一些特定强化会占用对应槽位。</p><p>支付C+1000，可以将OT-A09升级至C级，同时变更为以下内容：<br> 护甲值：20<br> 结构值：36<br> 体积：20<br> 移动速度：60米/轮<br> 载员：驾驶员1名，乘员2名，总体积不超过15<br> 动力系统：无限动力<br> 移动模式：地面，空中（机动性良好）</p><p>特性：脉冲炮/轨道炮，快启动，重型载具</p><p>【脉冲炮/轨道炮】：这视为一个单独的配件，需要额外支付250分才能加装。<br> 加装后你可以无需动作的为OT-A09凝聚出武装实体，随后在该场景内，每轮开始时驾驶员可以自行选择本轮使用脉冲炮或是轨道炮进行攻击，使用不同武器时会占用对应槽位。使用这两项武器需要的技能+专业为射击：脉冲炮/射击：轨道炮。</p><p>脉冲炮<br> 占用：武器槽位（两侧）<br> 分类：远程武器<br> 武器伤害：5L<br> 武器特性：【高速5】【破甲3】<br> 伤害类型：物理-穿刺<br> 基础射程：200米<br> 速射等级：无<br> 弹容量：【无限子弹】</p><p>轨道炮<br> 占用：武器槽位（左侧）<br> 分类：远程武器<br> 武器伤害：4L<br> 武器特性：【高速5】【贯穿】<br> 伤害类型：光能-能量伤害<br> 基础射程：100米<br> 速射等级：连射<br> 弹容量：【无限子弹】</p><p>【快启动】：OT-A09需要驾驶员使用移动动作展开人造梦雾区域，随后才能在本场景内正常作为载具使用。启动时驾驶员可以正常操纵OT-A09进行一次移动行为。未启动时，OT-A09不具有除【重型载具】以外的所有特性。</p><p>【重型载具】：OT-A09会为驾驶者和乘客提供全遮蔽效果，同时额外为驾驶者和乘客提供遮蔽防御，其数值为载具体积/被遮蔽者体积取低。<br> OT-A09具有左侧与右侧各一个武器槽位，同时具有装甲槽位，一些特定强化会占用对应槽位。</p><p>【僚机】：你可以从无人攻击机/蓄能甲板机/医疗无人机中选择一种获得，僚机分别具有不同的效果。<br> 【无人攻击机】：在使用OT-A09的武装进行攻击时可以额外选择2个目标，无法选择攻击过的目标；攻击造成的伤害增加2点，类型为攻击同类型伤害。<br> 【蓄能甲板机】：在受到攻击后的那一轮中，你可以选择一项与机械有关的能量池消耗减少1点，仅生效一次；蓄能甲板机会为OT-A09提供额外3点护甲值，以及免疫冲击点数减值的效果。<br> 【医疗无人机】：医疗无人机会为OT-A09提供2点快速维修（维修点数30）。</p><p>在C级的基础上，再支付B+2000，可以将OT-A09升级至B级，同时变更为以下内容：<br> 护甲值：28<br> 结构值：52<br> 体积：20<br> 移动速度：80米/轮<br> 载员：驾驶员1名，乘员2名，总体积不超过15<br> 动力系统：无限动力<br> 移动模式：地面，空中（机动性完美）</p><p>特性：脉冲炮/轨道炮，快启动，重型载具</p><p>【脉冲炮/轨道炮】：这视为一个单独的配件，需要额外支付250分才能加装。加装后你可以无需动作的为OT-A09凝聚出武装实体，随后在该场景内，每轮开始时驾驶员可以自行选择本轮使用脉冲炮或是轨道炮进行攻击，使用不同武器时会占用对应槽位。</p><p>脉冲炮<br> 占用：武器槽位（两侧）<br> 分类：远程武器<br> 武器伤害：5L<br> 武器特性：【高速5】【破甲3】<br> 伤害类型：物理-穿刺<br> 基础射程：200米<br> 速射等级：无<br> 弹容量：【无限子弹】</p><p>轨道炮<br> 占用：武器槽位（左侧）<br> 分类：远程武器<br> 武器伤害：4L<br> 武器特性：【高速5】【贯穿】<br> 伤害类型：光能-能量伤害<br> 基础射程：100米<br> 速射等级：连射<br> 弹容量：【无限子弹】</p><p>【快启动】：OT-A09需要驾驶员使用移动动作展开人造梦雾区域，随后才能在本场景内正常作为载具使用。启动时驾驶员可以正常操纵OT-A09进行一次移动行为。未启动时，OT-A09不具有除【重型载具】以外的所有特性。</p><p>【重型载具】：OT-A09会为驾驶者和乘客提供全遮蔽效果，同时额外为驾驶者和乘客提供遮蔽防御，其数值为载具体积/被遮蔽者体积取低，同时OT-A09具有【强拦截】特性。<br> OT-A09具有左侧与右侧各一个武器槽位，同时具有装甲槽位，一些特定强化会占用对应槽位。</p><p>【僚机】：每轮开始时，你可以从无人攻击机/蓄能甲板机/医疗无人机中选择一种效果获得，僚机分别具有不同的效果，僚机效果只能同时存在一种，且生效后本轮内会无法切换为其他僚机。<br> 【无人攻击机】：在使用OT-A09的武装进行攻击时可以额外选择2个目标，无法选择攻击过的目标；攻击造成的伤害增加2点，类型为攻击同类型伤害。<br> 【蓄能甲板机】：在受到攻击后的那一轮中，你可以选择一项与机械有关的能量池消耗减少1点，仅生效一次；蓄能甲板机会为OT-A09提供额外3点护甲值，以及免疫冲击点数减值的效果。<br> 【医疗无人机】：医疗无人机会为OT-A09提供2点快速维修（维修点数30）。</p><p>【破梦机：OT-A09专属武装】<br> 脉冲炮/轨道炮（强化）<br> 价格：D+500/C+1000/B+2000（差价）<br> 描述：<br> 效果：你需要在OT-A09已支付250分安装了脉冲炮/轨道炮的基础上，才能购买这一专属武装。<br> 根据该武器等级，对应武器伤害改为8L/7L（D级），13L/12L（C级），18L/19L，同时获得额外效果。<br> D级：攻击获得【破甲5】。<br> C级：攻击获得【毁灭】特性；获得【破甲5】。<br> B级：攻击获得【毁灭】与【幻灭】特性；获得【破甲10】，若计算目标防御后破甲仍有剩余，则这一效果提供的剩余破甲转为攻击检上的器械加值。</p><p>射击强化<br> 价格：C+1000<br> 描述：基本的强化射击，改良基础武器的性能，扩大杀伤范围。<br> 效果：<br> 购买后，你可以从【射击α】与【射击β】中选择一个效果获得。<br> 【射击α】：使用OT-A09的武装进行攻击时，改为对前方射程扇形范围内的所有敌对目标生效；此外，攻击额外获得3点附加成功数。<br> 【射击β】；使用OT-A09的武装进行攻击时，改为对前方射程直线内的所有敌对目标生效，你可以选择使目标采用反射豁免伤害而非正常防御；每轮一次，若你对攻击出目不满意则可以进行一次重骰，但必须接受重骰结果。</p><p>护甲强化<br> 价格：D+500/C+1000/B+2000（逐级）<br> 描述：基本的护甲强化，改良基础防护性能，虽然破梦机本身加装护甲也没什么意义，但更厚重的防护会在潜意识中让人觉得更难击破——自然也就产生了效果。<br> 效果：<br> D级：OT-A09获得额外5点护甲值，同时具有基于护甲值的【防弹】特性。<br> C级：保留之前等级效果，同时具有基于护甲值的【坚韧】【适应】特性。<br> B级：在之前等级的效果中，【坚韧】特性改为【超级坚韧】，额外护甲值数值改为获得等同驾驶员【智力/2+5】点，其他效果保留。</p><p>航空强化<br> 价格：C+1000<br> 描述：还原了梦破机在潜意识中作为“飞机”的性能，现在OT-A09可以如同一架飞机一样正常进行快速旅行了！<br> 效果：OT-A09的移动速度增加120米/轮；你现在可以操纵它进行加速类旅行，这需要驾驶员进行一个持续十分钟的加速准备行为，在这期间不可中断准备行为，在准备完成后即可以旅行速度进行旅行。当处于旅行状态时，默认失去所有动作，不可进入战斗轮（换句话说就是进入战斗则旅行速度失效）。这一级别的旅行速度等效于500公里的时速。</p><p>扩散锁定/收束照射<br> 前提：已购买脉冲炮/轨道炮（C级或以上）<br> 价格：C+1000<br> 描述：锁定后发射导弹，或是对前方敌人进行照射。在游戏当中是需要积累蓝色/品红色能量槽才能使用出的能力。<br> 效果：<br> 标准动作使用，使用脉冲炮/轨道炮进行攻击，对应发动扩散锁定或是收束照射，在购买时你从中选择一种获得，再支付相同的价格可以获得另一种效果。<br> 【扩散锁定】：本次攻击中加骰提升2级处理（上限8加骰），同时可以对攻击出目进行一次重骰，必须接受重骰结果（每轮一次）；若已购买射击强化（射击α），则可以额外支付1点意志力，使攻击获得【贯穿】特性。<br> 【收束照射】：本次攻击中的【毁灭】提升至【湮灭】，同时攻击获得【超级贯穿】特性；若已购买射击强化（射击β），则可以额外支付1点意志力，将直线改为前方锥形范围。<br> ——<br> 【购买这两项能力如同驾驶员购买了同级技艺一样处理，正常提供自由属性。】</p><p>反式-脉冲炮/反式-轨道炮<br> 价格：B+2500<br> 描述：锁定之后发射一连串的蓝色能量炮弹，或是发射覆盖半个屏幕大小的巨大能量光束。在游戏当中是触发梦境反噬但强行击破后才能使用的强力技能，由于涵盖了驾驶员本身的攻击欲望，能量中会夹杂着深邃的黑色。<br> 效果：<br> 标准动作使用，使用脉冲炮/轨道炮进行攻击，对应发动反式-脉冲炮/反式-轨道炮，在购买时你从中选择一种获得，再支付相同的价格可以获得另一种效果。<br> 【反式-脉冲炮】：进行两次无法附带其他招式的普通射击攻击，这两次攻击具有的加骰提升1级处理（上限8加骰），同时获得【湮灭】特性。<br> 【反式-轨道炮】：进行一次无法附带其他招式的普通射击攻击，这次攻击具有的加骰提升1级处理（上限8加骰），同时获得【湮灭】特性；本次攻击成功数增加一半处理，每轮只能使用一次。<br> ——<br> 【反式-脉冲炮/反式-轨道炮可由：扩散锁定/收束照射差价升级获得。】<br> 【购买这两项能力如同驾驶员购买了同级技艺一样处理，正常提供自由属性。】</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',34)])])}const c=p(A,[["render",O]]);export{i as __pageData,c as default};
